import{_ as a,o as e,c as r,a2 as t}from"./chunks/framework.DvFsUg-r.js";const p=JSON.parse('{"title":"플랫폼 관리 기능 이관 — Research (Phase 0)","description":"","frontmatter":{"title":"플랫폼 관리 기능 이관 — Research (Phase 0)","feature_id":"004","created":"2026-05-30 22:30 (KST)","date":"2026-05-30T00:00:00.000Z"},"headers":[],"relativePath":"specs/004-platform-admin-migration/research.md","filePath":"specs/004-platform-admin-migration/research.md","lastUpdated":null}'),i={name:"specs/004-platform-admin-migration/research.md"};function n(s,o,l,c,d,g){return e(),r("div",null,[...o[0]||(o[0]=[t('<h1 id="research-플랫폼-관리-기능-이관" tabindex="-1">Research: 플랫폼 관리 기능 이관 <a class="header-anchor" href="#research-플랫폼-관리-기능-이관" aria-label="Permalink to &quot;Research: 플랫폼 관리 기능 이관&quot;">​</a></h1><p>Phase 0 — plan 의 Technical Context 미확정(⏳) 항목과 이관 핵심 결정 정리.</p><h2 id="r1-mybatis-×-spring-boot-4-호환" tabindex="-1">R1. MyBatis × Spring Boot 4 호환 <a class="header-anchor" href="#r1-mybatis-×-spring-boot-4-호환" aria-label="Permalink to &quot;R1. MyBatis × Spring Boot 4 호환&quot;">​</a></h2><ul><li><strong>Decision</strong>: <strong><code>mybatis</code> 3.5.16 + <code>mybatis-spring</code> 3.0.4 직접 구성</strong> (<code>SqlSessionFactory</code>/<code>@MapperScan</code> 수동 빈)을 1순위로 고정한다. spike <strong>T0a</strong> 로 Spring Framework 7(Boot4) 동작을 착수 전 확인하고, 미호환이면 동일 메이저의 SF7 대응판으로 교체·재고정한다(스타터 없이 통합하므로 Boot 버전 의존 최소).</li><li><strong>Rationale</strong>: 소스가 MyBatis 기반이고 Clarification 으로 Oracle/MyBatis 유지가 확정됨. 스타터는 자동설정 편의일 뿐, 코어는 Boot 버전 비종속이라 직접 구성으로 항상 회피 경로가 있다.</li><li><strong>Alternatives considered</strong>: <ul><li>Spring Data JDBC/JPA 전환 → 매퍼 XML 재작성 비용 큼, 이관 충실도 저하. 기각.</li><li>Boot 3 으로 다운그레이드 → 헌법 Tech Baseline(Boot 4) 위반. 기각.</li></ul></li><li><strong>Gate</strong>: 채택 버전을 plan Version Lock 의 ⏳ → ✅ 로 갱신 후 구현.</li></ul><h2 id="r2-springdoc-openapi-×-spring-boot-4-호환" tabindex="-1">R2. springdoc-openapi × Spring Boot 4 호환 <a class="header-anchor" href="#r2-springdoc-openapi-×-spring-boot-4-호환" aria-label="Permalink to &quot;R2. springdoc-openapi × Spring Boot 4 호환&quot;">​</a></h2><ul><li><strong>Decision</strong>: <strong>범위 밖(보류)</strong>. Spring Boot 4(SF7) 대응판 확정 전까지 런타임 의존에 포함하지 않는다. OpenAPI UI 없이 22개 기능을 구현·검증한다.</li><li><strong>Rationale</strong>: API 문서는 부가기능. 본 기능의 성공기준(SC)과 무관하며, 미고정 의존성을 두지 않아 헌법 원칙2 를 깔끔히 충족.</li><li><strong>Alternatives</strong>: 수동 OpenAPI yaml 유지 — 과투자, 보류로 충분. 후속 도입 가능.</li></ul><h2 id="r3-인증-토큰-clarification-a4-토큰-유지" tabindex="-1">R3. 인증/토큰 (Clarification A4 = 토큰 유지) <a class="header-anchor" href="#r3-인증-토큰-clarification-a4-토큰-유지" aria-label="Permalink to &quot;R3. 인증/토큰 (Clarification A4 = 토큰 유지)&quot;">​</a></h2><ul><li><strong>Decision</strong>: 소스와 동일하게 <strong>JWT(jjwt 0.13.0)</strong> 기반 무상태 인증. Access(단기) <ul><li>Refresh(장기) 토큰, <code>/api/v1/auth</code> 의 login/refresh/logout/me. 비밀번호는 단방향 해시(BCrypt 상당).</li></ul></li><li><strong>Rationale</strong>: 소스 검증 패턴 답습, Spring Security stateless 와 정합.</li><li><strong>Alternatives</strong>: 세션 기반 → 무상태/수평확장 이점 상실, 소스와 불일치. 기각.</li></ul><h2 id="r4-감사·이력-기록-방식" tabindex="-1">R4. 감사·이력 기록 방식 <a class="header-anchor" href="#r4-감사·이력-기록-방식" aria-label="Permalink to &quot;R4. 감사·이력 기록 방식&quot;">​</a></h2><ul><li><strong>Decision</strong>: 상태변경은 <strong>AOP(<code>@AuditLog</code>)</strong> 로 <code>AUDIT_DATA_CHANGE</code> 기록, REST 호출은 <strong>인터셉터/필터</strong>로 <code>AUDIT_REST_LOG</code>, 예외는 <code>GlobalExceptionHandler</code> 에서 <code>AUDIT_EXCEPTION_LOG</code>, 메뉴 접근은 <code>/menus/{id}/access</code> + 인터셉터로 <code>AUDIT_MENU_ACCESS</code>, SQL 은 <strong>datasource-proxy 로 <code>AUDIT_SQL_LOG</code>(필수 — 22기능 포함)</strong>, 로그인은 인증 성공/실패 시 <code>SYS_LOGIN_HISTORY</code>, 파일은 파일 서비스에서 <code>AUDIT_FILE_LOG</code>. 모든 이력은 append-only.</li><li><strong>Rationale</strong>: 소스 audit 모듈 구조 그대로. 헌법 원칙 4(Observability) 강화.</li><li><strong>Alternatives</strong>: 수동 기록 호출 산재 → 누락 위험·중복. 기각.</li></ul><h2 id="r5-이력-보존-1년-정리-clarification-a6" tabindex="-1">R5. 이력 보존 1년 정리 (Clarification A6) <a class="header-anchor" href="#r5-이력-보존-1년-정리-clarification-a6" aria-label="Permalink to &quot;R5. 이력 보존 1년 정리 (Clarification A6)&quot;">​</a></h2><ul><li><strong>Decision</strong>: 생성 1년 경과 이력을 정리하는 <strong>스케줄 잡</strong>(예: 일 1회) + 보존경계 인덱스. 정리 방식은 삭제(또는 아카이브 테이블 이관) — 운영정책에 맞춰 설정값화(<code>SYS_SETTING</code> 키).</li><li><strong>Rationale</strong>: SC-9(1년 경과분 조회 제외, 1년 이내 100% 보존) 충족.</li><li><strong>Alternatives</strong>: 무기한 보존 → Clarification 으로 기각됨.</li></ul><h2 id="r6-데이터-마이그레이션-범위" tabindex="-1">R6. 데이터 마이그레이션 범위 <a class="header-anchor" href="#r6-데이터-마이그레이션-범위" aria-label="Permalink to &quot;R6. 데이터 마이그레이션 범위&quot;">​</a></h2><ul><li><strong>Decision</strong>: <strong>기능/스키마 이관만</strong>. 기존 운영 데이터 이행은 비목표. 초기 <strong>최소 시드</strong>(관리자 계정·기본 역할·기본 메뉴 트리·필수 공통코드)만 changeset 으로.</li><li><strong>Rationale</strong>: spec Non-goals 및 A5 와 일치.</li></ul><h2 id="r7-빌드-도구-maven-→-gradle" tabindex="-1">R7. 빌드 도구 (Maven → Gradle) <a class="header-anchor" href="#r7-빌드-도구-maven-→-gradle" aria-label="Permalink to &quot;R7. 빌드 도구 (Maven → Gradle)&quot;">​</a></h2><ul><li><strong>Decision</strong>: 타겟 <code>app</code> 의 <strong>Gradle(Kotlin DSL)</strong> 유지. 소스 pom 의존성을 Gradle 표기로 적응. 프론트 빌드 통합(frontend-maven-plugin) 불필요(표면은 정적 데모) → 제외.</li><li><strong>Rationale</strong>: 타겟 규약 적응 이식(A1).</li></ul><h2 id="r8-표면-데모-대상-—-spec-open-question-해소" tabindex="-1">R8. 표면(데모) 대상 — spec Open Question 해소 <a class="header-anchor" href="#r8-표면-데모-대상-—-spec-open-question-해소" aria-label="Permalink to &quot;R8. 표면(데모) 대상 — spec Open Question 해소&quot;">​</a></h2><ul><li><strong>Decision</strong>: VuGrid 데모는 <strong>사용자 목록 + 로그인 이력 2종</strong>으로 한정(조회 위주). 나머지 기능은 API 로 제공, UI 완전 이식은 후속 비목표.</li><li><strong>Rationale</strong>: 003 의 &quot;최소 데모&quot; 방향 + A2. 범위 폭주 방지.</li></ul><h2 id="미해소-잔여-—-비차단" tabindex="-1">미해소(잔여) — 비차단 <a class="header-anchor" href="#미해소-잔여-—-비차단" aria-label="Permalink to &quot;미해소(잔여) — 비차단&quot;">​</a></h2><ul><li>메일 <strong>실발송(SMTP)</strong> 연결 여부: 본 기능은 발송 시도/결과 <strong>기록·재시도 진입점</strong> 까지. 실 SMTP 연동은 운영 설정값(<code>SYS_SETTING</code>)으로 분리, 데모는 기록 검증 위주.</li></ul>',20)])])}const u=a(i,[["render",n]]);export{p as __pageData,u as default};
